pub struct BlockingCanonStateNotifier<N: NodePrimitives> {
    handlers: Mutex<Vec<BlockingHandler<N>>>,
}

pub fn new() -> Self {
    Self { handlers: Mutex::new(Vec::new()) }
}

pub type BlockingHandler<N> = Arc<dyn Fn(&Chain<N>) + Send + Sync>;

pub fn subscribe(&self, handler: BlockingHandler<N>) {
    if let Ok(mut handlers) = self.handlers.lock() {
        handlers.push(handler);
    }
}

